// Learn: Collect stream results into lists.
import java.util.List;
import java.util.stream.Collectors;

class User {
  final String name, email;
  final boolean active;
  User(String name, String email, boolean active) {
    this.name = name; this.email = email; this.active = active;
  }
  String name() { return name; }
  String email() { return email; }
  boolean active() { return active; }
}

List<User> users = List.of(
  new User("Ada", "ada@example.com", true),
  new User("Ben", "ben@example.com", false)
);

List<String> activeNames = users.stream()
  // filter removes inactive users before mapping names.
  .filter(User::active)
  .map(User::name)
  .collect(Collectors.toList());

List<String> emails = users.stream()
  .map(User::email)
  .toList();
